public enum FederationNamenodeServiceState {
  ACTIVE, // HAServiceState.ACTIVE or operational.
  OBSERVER, // HAServiceState.OBSERVER.
  STANDBY, // HAServiceState.STANDBY.
  UNAVAILABLE, // When the namenode cannot be reached.
  EXPIRED, // When the last update is too old.
  DISABLED; // When the nameservice is disabled.

  public static FederationNamenodeServiceState getState(HAServiceState state) {
    switch(state) {
    case ACTIVE:
      return FederationNamenodeServiceState.ACTIVE;
    case OBSERVER:
      return FederationNamenodeServiceState.OBSERVER;
    case STANDBY:
      return FederationNamenodeServiceState.STANDBY;
    case INITIALIZING:
      return FederationNamenodeServiceState.UNAVAILABLE;
    case STOPPING:
      return FederationNamenodeServiceState.UNAVAILABLE;
    default:
      return FederationNamenodeServiceState.UNAVAILABLE;
    }
  }
}

final class TrackingTmpOutputDirectoryWrapper extends FilterDirectory {
  private final Map<String, String> fileNames = new HashMap<>();

  TrackingTmpOutputDirectoryWrapper(Directory in) {
    super(in);
  }

  @Override
  public IndexOutput createOutput(String name, IOContext context) throws IOException {
    IndexOutput output = super.createTempOutput(name, "", context);
    fileNames.put(name, output.getName());
    return output;
  }

  @Override
  public IndexInput openInput(String name, IOContext context) throws IOException {
    // keep the original file name if no match, it might be a temp file already
    String tmpName = fileNames.getOrDefault(name, name);
    return super.openInput(tmpName, context);
  }

  public Map<String, String> getTemporaryFiles() {
    return fileNames;
  }
}

public class PositiveScoresOnlyCollector extends FilterCollector {

  public PositiveScoresOnlyCollector(Collector in) {
    super(in);
  }

  @Override
  public LeafCollector getLeafCollector(LeafReaderContext context) throws IOException {
    return ScoreCachingWrappingScorer.wrap(
        new FilterLeafCollector(super.getLeafCollector(context)) {

          private Scorable scorer;

          @Override
          public void setScorer(Scorable scorer) throws IOException {
            this.scorer = scorer;
            in.setScorer(scorer);
          }

          @Override
          public void collect(int doc) throws IOException {
            if (scorer.score() > 0) {
              in.collect(doc);
            }
          }
        });
  }
}

@BugPattern(
    summary =
        "Static and default interface methods are not natively supported on older Android devices."
            + " ",
    severity = ERROR,
    documentSuppression = false // for slightly customized suppression documentation
    )
public class StaticOrDefaultInterfaceMethod extends BugChecker implements MethodTreeMatcher {

  private static final Matcher<Tree> IS_STATIC_OR_DEFAULT_METHOD_ON_INTERFACE =
      allOf(enclosingClass(kindIs(INTERFACE)), anyOf(hasModifier(STATIC), hasModifier(DEFAULT)));

  @Override
  public Description matchMethod(MethodTree tree, VisitorState state) {
    if (!state.isAndroidCompatible()) {
      return Description.NO_MATCH;
    }
    if (IS_STATIC_OR_DEFAULT_METHOD_ON_INTERFACE.matches(tree, state)) {
      return describeMatch(tree);
    }
    return Description.NO_MATCH;
  }
}

public class InvocationMarker {

    private InvocationMarker() {}

    public static void markVerified(List<Invocation> invocations, MatchableInvocation wanted) {
        for (Invocation invocation : invocations) {
            markVerified(invocation, wanted);
        }
    }

    public static void markVerified(Invocation invocation, MatchableInvocation wanted) {
        invocation.markVerified();
        wanted.captureArgumentsFrom(invocation);
    }

    public static void markVerifiedInOrder(
            List<Invocation> chunk, MatchableInvocation wanted, InOrderContext context) {
        markVerified(chunk, wanted);

        for (Invocation i : chunk) {
            context.markVerified(i);
        }
    }
}

